import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';

const Badge = ({ status }) => {
  const colors = { PENDING: '#f59e0b', APPROVED: '#22c55e', REJECTED: '#ef4444' };
  const c = colors[status] || '#94a3b8';
  return <span style={{ padding: '3px 10px', borderRadius: 99, background: c + '20', color: c, fontWeight: 700, fontSize: 12 }}>{status}</span>;
};

export default function AdminLoans() {
  const [loans, setLoans] = useState([]);
  const [filter, setFilter] = useState('ALL');
  const [comment, setComment] = useState('');
  const [rejectId, setRejectId] = useState(null);

  const fetchLoans = () => axiosInstance.get('/loans').then(r => setLoans(r.data.loans || []));
  useEffect(() => { fetchLoans(); }, []);

  const approve = async (loanId) => {
    try { await axiosInstance.patch(`/loans/${loanId}/approve`); toast.success('Loan approved & disbursed!'); fetchLoans(); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const reject = async (loanId) => {
    try { await axiosInstance.patch(`/loans/${loanId}/reject`, { adminComment: comment || 'Rejected by admin' }); toast.success('Loan rejected'); fetchLoans(); setRejectId(null); setComment(''); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const filtered = filter === 'ALL' ? loans : loans.filter(l => l.status === filter);

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 style={{ margin: '0 0 24px', color: '#1e293b' }}> Loan Applications</h2>
      </div>

      <div className="d-flex flex-wrap gap-2 mb-4">
        {['ALL', 'PENDING', 'APPROVED', 'REJECTED'].map(s => (
          <button key={s} onClick={() => setFilter(s)}
            style={{ padding: '6px 14px', borderRadius: 99, border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: 12,
              background: filter === s ? '#1e293b' : '#fff', color: filter === s ? '#fff' : '#64748b', boxShadow: '0 1px 4px rgba(0,0,0,0.08)' }}>
            {s}
          </button>
        ))}
      </div>

      {rejectId && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 16 }}>
          <div style={{ background: '#fff', borderRadius: 12, padding: 28, width: '100%', maxWidth: 400 }}>
            <h3 style={{ margin: '0 0 16px' }}>Reject Loan</h3>
            <textarea value={comment} onChange={e => setComment(e.target.value)} placeholder="Reason for rejection (optional)"
              style={{ width: '100%', padding: '10px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, resize: 'vertical', minHeight: 80, boxSizing: 'border-box', marginBottom: 16 }} />
            <div className="d-flex gap-2">
              <button onClick={() => reject(rejectId)} style={{ flex: 1, padding: 12, borderRadius: 8, border: 'none', background: '#ef4444', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>Reject</button>
              <button onClick={() => { setRejectId(null); setComment(''); }} style={{ flex: 1, padding: 12, borderRadius: 8, border: 'none', background: '#f1f5f9', color: '#64748b', fontWeight: 700, cursor: 'pointer' }}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
        {filtered.map(loan => (
          <div key={loan.loanId} style={{ background: '#fff', borderRadius: 12, padding: 24, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
            <div className="d-flex flex-wrap justify-content-between align-items-start gap-2 mb-3">
              <div>
                <span style={{ fontFamily: 'monospace', fontSize: 12, color: '#94a3b8' }}>{loan.loanId}</span>
                <div className="d-flex flex-wrap gap-3 mt-1">
                  <span style={{ fontSize: 12, color: '#64748b' }}>Customer: <strong>{loan.customerId}</strong></span>
                  <span style={{ fontSize: 12, color: '#64748b' }}>Account: <strong style={{ fontFamily: 'monospace' }}>{loan.accountNumber}</strong></span>
                </div>
              </div>
              <Badge status={loan.status} />
            </div>
            <div className="d-flex flex-wrap gap-4 mb-3">
              {[['Loan Amount', `₹${loan.loanAmount?.toLocaleString('en-IN')}`], ['EMI', `₹${loan.emi?.toLocaleString('en-IN')}/mo`], ['Tenure', `${loan.tenureMonths} months`], ['Rate', `${loan.interestRate}%`], ['Purpose', loan.purpose], ['Applied', new Date(loan.createdAt).toLocaleDateString('en-IN')]].map(([lbl, val]) => (
                <div key={lbl}><p style={{ margin: 0, color: '#94a3b8', fontSize: 11 }}>{lbl}</p><p style={{ margin: 0, fontWeight: 700, fontSize: 14 }}>{val}</p></div>
              ))}
            </div>
            {loan.adminComment && <p style={{ fontSize: 13, color: '#ef4444', margin: '0 0 12px' }}>Note: {loan.adminComment}</p>}
            {loan.status === 'PENDING' && (
              <div className="d-flex flex-wrap gap-2">
                <button onClick={() => approve(loan.loanId)} style={{ padding: '8px 20px', borderRadius: 8, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700, cursor: 'pointer' }}> Approve &amp; Disburse</button>
                <button onClick={() => setRejectId(loan.loanId)} style={{ padding: '8px 20px', borderRadius: 8, border: 'none', background: '#ef4444', color: '#fff', fontWeight: 700, cursor: 'pointer' }}> Reject</button>
              </div>
            )}
          </div>
        ))}
        {filtered.length === 0 && <div style={{ background: '#fff', borderRadius: 12, padding: 32, textAlign: 'center', color: '#94a3b8' }}>No loans found</div>}
      </div>
    </Layout>
  );
}
